class Solution:
    def highestRankedKItems(self, grid, pricing, start, k):
        low, high = pricing[0], pricing[1]
        m, n = len(grid), len(grid[0])
        sr, sc = start[0], start[1]
        INF = float('inf')
        dist = [[INF] * n for _ in range(m)]
        dist[sr][sc] = 0
        # Bellman-Ford-style repeated relaxation over the grid graph until
        # no distance improves -- a deliberately different mechanism than a
        # queue-based BFS, but correct for unit-weight, no-negative-cycle graphs.
        changed = True
        while changed:
            changed = False
            for r in range(m):
                for c in range(n):
                    if grid[r][c] == 0 or dist[r][c] == INF:
                        continue
                    for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] != 0:
                            if dist[r][c] + 1 < dist[nr][nc]:
                                dist[nr][nc] = dist[r][c] + 1
                                changed = True
        items = []
        for r in range(m):
            for c in range(n):
                if dist[r][c] < INF and low <= grid[r][c] <= high:
                    items.append((dist[r][c], grid[r][c], r, c))
        items.sort()
        return [[r, c] for _, _, r, c in items[:k]]

