var highestRankedKItems = function(grid, pricing, start, k) {
    const low = pricing[0], high = pricing[1];
    const m = grid.length, n = grid[0].length;
    const sr = start[0], sc = start[1];
    const visited = Array.from({ length: m }, () => new Array(n).fill(false));
    visited[sr][sc] = true;
    const queue = [[sr, sc, 0]];
    let head = 0;
    const items = [];
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    while (head < queue.length) {
        const [r, c, d] = queue[head++];
        const price = grid[r][c];
        if (price >= low && price <= high) {
            items.push([d, price, r, c]);
        }
        for (const [dr, dc] of dirs) {
            const nr = r + dr, nc = c + dc;
            if (nr >= 0 && nr < m && nc >= 0 && nc < n && !visited[nr][nc] && grid[nr][nc] !== 0) {
                visited[nr][nc] = true;
                queue.push([nr, nc, d + 1]);
            }
        }
    }
    items.sort((a, b) => a[0] - b[0] || a[1] - b[1] || a[2] - b[2] || a[3] - b[3]);
    return items.slice(0, k).map(t => [t[2], t[3]]);
};
